class Solution:
    def hitBricks(self, grid, hits):
        from collections import deque
        m = len(grid)
        n = len(grid[0])
        g = [row[:] for row in grid]
        def stable_set():
            seen = [[False] * n for _ in range(m)]
            q = deque()
            for c in range(n):
                if g[0][c] == 1:
                    seen[0][c] = True
                    q.append((0, c))
            while q:
                r, c = q.popleft()
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and g[nr][nc] == 1 and not seen[nr][nc]:
                        seen[nr][nc] = True
                        q.append((nr, nc))
            return seen
        res = []
        for r, c in hits:
            if g[r][c] == 0:
                res.append(0)
                continue
            g[r][c] = 0
            stable = stable_set()
            fell = 0
            for i in range(m):
                for j in range(n):
                    if g[i][j] == 1 and not stable[i][j]:
                        g[i][j] = 0
                        fell += 1
            res.append(fell)
        return res

