class Solution:
    def hitBricks(self, grid, hits):
        m = len(grid)
        n = len(grid[0])
        g = [row[:] for row in grid]
        for r, c in hits:
            g[r][c] -= 1
        TOP = m * n
        parent = list(range(m * n + 1))
        size = [1] * (m * n + 1)
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if size[ra] < size[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            size[ra] += size[rb]
        def idx(r, c):
            return r * n + c
        for r in range(m):
            for c in range(n):
                if g[r][c] == 1:
                    if r == 0:
                        union(idx(r, c), TOP)
                    if r > 0 and g[r - 1][c] == 1:
                        union(idx(r, c), idx(r - 1, c))
                    if c > 0 and g[r][c - 1] == 1:
                        union(idx(r, c), idx(r, c - 1))
        def top_size():
            return size[find(TOP)] - 1
        res = [0] * len(hits)
        for i in range(len(hits) - 1, -1, -1):
            r, c = hits[i]
            if grid[r][c] == 0:
                res[i] = 0
                continue
            before = top_size()
            g[r][c] = 1
            if r == 0:
                union(idx(r, c), TOP)
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n and g[nr][nc] == 1:
                    union(idx(r, c), idx(nr, nc))
            after = top_size()
            res[i] = max(0, after - before - 1)
        return res

