var hitBricks = function(grid, hits) {
    const m = grid.length, n = grid[0].length;
    const g = grid.map(row => row.slice());
    for (const [r, c] of hits) g[r][c] -= 1;
    const TOP = m * n;
    const parent = new Array(m * n + 1);
    const size = new Array(m * n + 1).fill(1);
    for (let i = 0; i <= m * n; i++) parent[i] = i;
    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    function union(a, b) {
        let ra = find(a), rb = find(b);
        if (ra === rb) return;
        if (size[ra] < size[rb]) { const t = ra; ra = rb; rb = t; }
        parent[rb] = ra;
        size[ra] += size[rb];
    }
    const idx = (r, c) => r * n + c;
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (g[r][c] === 1) {
                if (r === 0) union(idx(r, c), TOP);
                if (r > 0 && g[r - 1][c] === 1) union(idx(r, c), idx(r - 1, c));
                if (c > 0 && g[r][c - 1] === 1) union(idx(r, c), idx(r, c - 1));
            }
        }
    }
    const topSize = () => size[find(TOP)] - 1;
    const res = new Array(hits.length).fill(0);
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    for (let i = hits.length - 1; i >= 0; i--) {
        const [r, c] = hits[i];
        if (grid[r][c] === 0) { res[i] = 0; continue; }
        const before = topSize();
        g[r][c] = 1;
        if (r === 0) union(idx(r, c), TOP);
        for (const [dr, dc] of dirs) {
            const nr = r + dr, nc = c + dc;
            if (nr >= 0 && nr < m && nc >= 0 && nc < n && g[nr][nc] === 1) union(idx(r, c), idx(nr, nc));
        }
        const after = topSize();
        res[i] = Math.max(0, after - before - 1);
    }
    return res;
};
